    87	  public constructor(code: string, options: { cause?: unknown; providerStatus?: number } = {}) {
    88	    super(
    89	      "OIDC JWKS provider failure",
    90	      options.cause === undefined ? undefined : { cause: options.cause },
    91	    );
    92	    this.code = code;
    93	    this.name = "OidcProviderJwksError";
    94	    this.providerStatus = options.providerStatus;
