   142	function classifyVerificationError(error: unknown): OidcTokenVerifierFailure {
   143	  const errorCode = errorCodeOf(error);
   144	
   145	  if (error instanceof OidcProviderJwksError) {
   146	    return providerFailure(errorCode, error.providerStatus);
   147	  }
   148	
   149	  if (error instanceof errors.JOSEError) {
   150	    if (invalidTokenErrorCodes.has(error.code)) {
   151	      return invalidTokenFailure(error.code);
   152	    }
   153	
   154	    if (providerFailureErrorCodes.has(error.code)) {
   155	      return providerFailure(error.code);
   156	    }
   157	
   158	    return verifierFailure(error.code);
   159	  }
   160	
   161	  return verifierFailure(errorCode);
   162	}
   163	
   164	const invalidTokenErrorCodes = new Set([
   165	  "ERR_JOSE_ALG_NOT_ALLOWED",
   166	  // The caller controls the JWT header kid. If the provider returns a valid JWKS
   167	  // that does not contain that key, treat the assertion as invalid rather than
   168	  // retryable provider unavailability.
   169	  "ERR_JWKS_NO_MATCHING_KEY",
   170	  "ERR_JWS_INVALID",
   171	  "ERR_JWS_SIGNATURE_VERIFICATION_FAILED",
   172	  "ERR_JWT_CLAIM_VALIDATION_FAILED",
   173	  "ERR_JWT_EXPIRED",
   174	  "ERR_JWT_INVALID",
   175	]);
   176	
   177	const providerFailureErrorCodes = new Set([
   178	  "ERR_JOSE_NOT_SUPPORTED",
   179	  "ERR_JWK_INVALID",
   180	  "ERR_JWKS_INVALID",
   181	  "ERR_JWKS_MULTIPLE_MATCHING_KEYS",
   182	  "ERR_JWKS_TIMEOUT",
   183	]);
   184	
   185	function invalidTokenFailure(errorCode?: string): OidcTokenVerifierFailure {
   186	  return {
   187	    ...(errorCode === undefined ? {} : { errorCode }),
   188	    ok: false,
   189	    reason: "invalid_token",
   190	  };
   191	}
   192	
   193	function providerFailure(errorCode?: string, providerStatus?: number): OidcTokenVerifierFailure {
   194	  return {
   195	    ...(errorCode === undefined ? {} : { errorCode }),
   196	    ok: false,
   197	    ...(providerStatus === undefined ? {} : { providerStatus }),
   198	    reason: "provider_failure",
   199	  };
   200	}
   201	
   202	function verifierFailure(errorCode?: string): OidcTokenVerifierFailure {
   203	  return {
   204	    ...(errorCode === undefined ? {} : { errorCode }),
   205	    ok: false,
   206	    reason: "verifier_failure",
   207	  };
   208	}
   209	
   210	function errorCodeOf(error: unknown): string | undefined {
   211	  if (typeof error === "object" && error !== null && "code" in error) {
   212	    const code = error.code;
   213	
   214	    if (typeof code === "string") {
   215	      return code;
   216	    }
   217	  }
   218	
   219	  return undefined;
   220	}
   221	
   222	function hasErrorName(error: unknown, name: string): boolean {
   223	  return (
   224	    typeof error === "object" &&
   225	    error !== null &&
   226	    "name" in error &&
   227	    typeof error.name === "string" &&
   228	    error.name === name
   229	  );
   230	}
   231	
   232	function isJsonWebKeySetShape(input: unknown): input is { keys: unknown[] } {
   233	  return (
   234	    typeof input === "object" &&
   235	    input !== null &&
   236	    "keys" in input &&
   237	    Array.isArray(input.keys) &&
   238	    input.keys.every((key) => typeof key === "object" && key !== null)
   239	  );
