   117	const oidcVerifiers = new WeakMap<TrustedOidcIssuer, OidcTokenVerifier>();
   118	
   119	function trustedIssuerForSubjectToken(
   120	  token: string,
   121	  issuerAdapters: readonly OidcIssuerAdapter[],
   122	):
   123	  | {
   124	      adapter: OidcIssuerAdapter;
   125	      issuer: TrustedOidcIssuer;
   126	      ok: true;
   127	    }
   128	  | { ok: false; reason: AuthenticateRequestFailureReason } {
   129	  const issuer = unverifiedIssuer(token);
   130	
   131	  if (issuer === null) {
   132	    return { ok: false, reason: "invalid_token" };
   133	  }
   134	
   135	  for (const adapter of issuerAdapters) {
   136	    const trustedIssuers = adapter.trustedIssuers;
   137	
   138	    if (trustedIssuers === null) {
   139	      if (adapter.canHandleIssuer(issuer)) {
   140	        return { ok: false, reason: "oidc_verifier_failure" };
   141	      }
   142	
   143	      continue;
   144	    }
   145	
   146	    for (const trustedIssuer of trustedIssuers) {
   147	      if (issuer === trustedIssuer.issuer) {
   148	        return {
   149	          adapter,
   150	          issuer: trustedIssuer,
   151	          ok: true,
   152	        };
   153	      }
   154	    }
   155	  }
   156	
   157	  return { ok: false, reason: "invalid_token" };
   158	}
   159	
   160	function oidcVerifierForTrustedIssuer(
   161	  issuer: TrustedOidcIssuer,
   162	  fetchJwks: typeof fetch | undefined,
   163	): OidcTokenVerifier {
   164	  if (fetchJwks !== undefined) {
   165	    return new OidcTokenVerifier({
   166	      fetchJwks,
   167	      issuer,
   168	    });
   169	  }
   170	
   171	  const cachedVerifier = oidcVerifiers.get(issuer);
   172	
   173	  if (cachedVerifier !== undefined) {
   174	    return cachedVerifier;
   175	  }
   176	
   177	  const verifier = new OidcTokenVerifier({ issuer });
   178	  oidcVerifiers.set(issuer, verifier);
   179	
   180	  return verifier;
   181	}
