   203	
   204	  console.warn("OIDC authentication failed", {
   205	    path: url.pathname,
   206	    rayId: request.headers.get("cf-ray"),
   207	    reason,
   208	    ...(diagnostics.errorCode === undefined ? {} : { errorCode: diagnostics.errorCode }),
   209	    ...(diagnostics.providerStatus === undefined
   210	      ? {}
   211	      : { providerStatus: diagnostics.providerStatus }),
