   216	function authenticationFailureReasonForVerifierFailure(
   217	  reason: "invalid_token" | "provider_failure" | "verifier_failure",
   218	): AuthenticateRequestFailureReason {
   219	  if (reason === "provider_failure") {
   220	    return "oidc_provider_failure";
   221	  }
   222	
   223	  if (reason === "verifier_failure") {
   224	    return "oidc_verifier_failure";
   225	  }
   226	
   227	  return "invalid_token";
   228	}

