     2	  createInstallationTokenForRepository,
     3	  resolveInstallationForRepository,
     4	} from "@cyspbot/github/app";
     5	import { GitHubApiError, type GitHubApiDependencies } from "@cyspbot/github/http";
     6	import type { AuthenticatedContext, VerifiedSubjectToken } from "../authentication.ts";
     7	import {
     8	  evaluateConfiguredTokenPolicy,
     9	  parseGitHubRepositoryResource,
    10	  type InstallationAccessTokenRequest,
    11	  type TokenPolicyDecision,
    12	  type TokenPolicyRule,
    13	} from "./token-policy.ts";
    14	import { tokenPolicyRules as defaultTokenPolicyRules } from "./token-policy-rules.ts";
    15	
    16	export interface InstallationTokenIssuanceDependencies extends GitHubApiDependencies {
    17	  tokenPolicyRules?: readonly TokenPolicyRule[];
    18	}
    19	
    20	export type InstallationTokenIssuanceResult =
    21	  | { expiresAt: string; ok: true; token: string }
    22	  | { ok: false; status: number };
    23	
    24	class TokenPolicyDeniedError extends Error {
    25	  public readonly policyDecision: TokenPolicyDecision;
    26	
    27	  public constructor(policyDecision: TokenPolicyDecision) {
    28	    super("Token Policy denied Installation Token Issuance");
    29	    this.policyDecision = policyDecision;
    30	  }
    31	}
    32	
    33	export async function issueInstallationTokenForContext(
    34	  env: TokenExchangeBindings,
    35	  authenticationContext: AuthenticatedContext,
    36	  tokenRequest: InstallationAccessTokenRequest,
    37	  dependencies: InstallationTokenIssuanceDependencies,
    38	): Promise<InstallationTokenIssuanceResult> {
    39	  const { subjectToken } = authenticationContext;
    40	  let policyDecision: TokenPolicyDecision | undefined;
    41	  let targetInstallationId: number | undefined;
    42	
    43	  try {
    44	    policyDecision = evaluateConfiguredTokenPolicy(
    45	      {
    46	        subjectToken,
    47	        tokenRequest,
    48	      },
    49	      dependencies.tokenPolicyRules ?? defaultTokenPolicyRules,
    50	    );
    51	
    52	    if (policyDecision.decision !== "allow") {
    53	      throw new TokenPolicyDeniedError(policyDecision);
    54	    }
    55	
    56	    const requestedResource = parseGitHubRepositoryResource(tokenRequest.resource.href);
    57	
    58	    if (requestedResource === null) {
    59	      throw new GitHubApiError(400, "invalid token request resource");
    60	    }
    61	
    62	    const requestedResourceName = `${requestedResource.owner}/${requestedResource.repository}`;
    63	    const targetInstallation = await resolveInstallationForRepository(
    64	      env,
    65	      requestedResourceName,
    66	      dependencies,
    67	    );
    68	    targetInstallationId = targetInstallation.id;
    69	    const installationToken = await createInstallationTokenForRepository(
    70	      env,
    71	      targetInstallation.id,
    72	      requestedResourceName,
    73	      tokenRequest.permissions,
    74	      dependencies,
    75	    );
    76	
    77	    console.info({
    78	      event: "installation_token_issuance_succeeded",
    79	      expires_at: installationToken.expiresAt,
    80	      subject_token: subjectTokenLogFields(authenticationContext),
    81	      target_installation: {
    82	        id: targetInstallation.id,
    83	        repository: requestedResourceName,
    84	      },
    85	      token_policy: {
    86	        matched: true,
    87	        rule_id: policyDecision.matchedRule.id,
    88	      },
    89	      token_request: tokenRequestLogFields(tokenRequest),
    90	    });
    91	
    92	    return {
    93	      expiresAt: installationToken.expiresAt,
    94	      ok: true,
    95	      token: installationToken.token,
    96	    };
    97	  } catch (error) {
    98	    const status = statusForInstallationTokenIssuanceError(error);
    99	
   100	    console.error({
   101	      error: {
   102	        message: logMessageForInstallationTokenIssuanceError(error),
   103	        name: error instanceof Error ? error.name : typeof error,
   104	        status: error instanceof GitHubApiError ? error.status : undefined,
   105	      },
   106	      event: "installation_token_issuance_failed",
   107	      subject_token: subjectTokenLogFields(authenticationContext),
   108	      target_installation: {
   109	        id: targetInstallationId,
   110	      },
   111	      token_policy: tokenPolicyLogFields(error, policyDecision),
   112	      token_request: tokenRequestLogFields(tokenRequest),
   113	    });
   114	
   115	    return { ok: false, status };
   116	  }
   117	}
   118	
   119	function statusForInstallationTokenIssuanceError(error: unknown): number {
   120	  if (error instanceof TokenPolicyDeniedError) {
   121	    return 403;
   122	  }
   123	
   124	  if (error instanceof Response) {
   125	    return error.status;
   126	  }
   127	
   128	  if (error instanceof GitHubApiError) {
   129	    if (error.status === 400) {
   130	      return 500;
   131	    }
   132	
   133	    if (error.status === 401 || error.status === 403 || error.status === 404) {
   134	      return 403;
   135	    }
   136	
   137	    if (error.status >= 500) {
   138	      return 502;
   139	    }
   140	  }
   141	
   142	  return 500;
   143	}
   144	
   145	function logMessageForInstallationTokenIssuanceError(error: unknown): string {
   146	  if (error instanceof GitHubApiError || error instanceof TokenPolicyDeniedError) {
   147	    return error.message;
   148	  }
   149	
   150	  return "unexpected Installation Token Issuance error";
   151	}
   152	
   153	function subjectTokenLogFields(
   154	  authenticationContext: AuthenticatedContext,
   155	): Record<string, unknown> {
   156	  return {
   157	    issuer: authenticationContext.subjectToken.issuer,
   158	    resolved_key_id: authenticationContext.subjectToken.resolvedKeyId,
   159	    sub: subjectTokenSubjectLogValue(authenticationContext.subjectToken),
   160	    subject_token_type: authenticationContext.subjectToken.subjectTokenType,
   161	  };
   162	}
   163	
   164	function subjectTokenSubjectLogValue(subjectToken: VerifiedSubjectToken): string | null {
   165	  const subject = subjectToken.claims.sub;
   166	
   167	  return typeof subject === "string" ? subject : null;
   168	}
   169	
   170	function tokenRequestLogFields(
   171	  tokenRequest: InstallationAccessTokenRequest,
   172	): Record<string, unknown> {
   173	  return {
   174	    permissions: tokenRequest.permissions,
   175	    resource: tokenRequest.resource.href,
   176	    scope: tokenRequest.scope,
   177	  };
   178	}
   179	
   180	function tokenPolicyLogFields(
   181	  error: unknown,
   182	  policyDecision: TokenPolicyDecision | undefined,
   183	): Record<string, unknown> {
   184	  if (error instanceof TokenPolicyDeniedError) {
   185	    return {
   186	      deny_reasons:
   187	        error.policyDecision.decision === "deny" ? error.policyDecision.reasons : undefined,
   188	      matched: false,
   189	    };
   190	  }
   191	
   192	  if (policyDecision?.decision === "allow") {
   193	    return {
   194	      matched: true,
   195	      rule_id: policyDecision.matchedRule.id,
   196	    };
   197	  }
   198	
   199	  return {
   200	    matched: false,
   201	  };
   202	}

